import type React from 'react';

import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '../../utils/cn';

const sectionVariants = cva('flex flex-col rounded', {
  variants: {
    size: {
      md: 'gap-2 p-3',
      lg: 'gap-3 p-4',
      xl: 'gap-4 p-6',
    },
    color: {
      default: 'border bg-card',
      danger: 'border border-card-danger-border bg-card-danger',
    },
  },
  defaultVariants: {
    size: 'md',
    color: 'default',
  },
});

/**
 * Guidewheel design pattern presentational component for a section of a page.
 */
function PageSection({
  className,
  children,
  size,
  color,
  ...props
}: React.ComponentProps<'div'> & VariantProps<typeof sectionVariants>) {
  return (
    <div className={cn(sectionVariants({ size, color }), className)} {...props}>
      {children}
    </div>
  );
}

export { PageSection };
